-- ================================================================
-- ProductImages Fix v2 — No IDENTITY_INSERT, TRY/CATCH safety
-- Logic:
--   1. DELETE all images for each product
--   2. Insert NULL-variantId rows (Zone A = common photos)
--   3. Insert per-variantId rows (Zone B = color-specific)
-- ================================================================

BEGIN TRY

-- Step 1: Delete all existing ProductImages (FK safe — no child tables)
DELETE FROM [ProductImages];
PRINT 'Deleted all existing ProductImages';














































































































































































































































































































PRINT 'SUCCESS: Inserted 4194 ProductImage rows';

END TRY
BEGIN CATCH
    PRINT 'ERROR: ' + ERROR_MESSAGE();
    PRINT 'Line: ' + CAST(ERROR_LINE() AS VARCHAR);
    -- ROLLBACK if needed
END CATCH

GO
-- Total: 4194 rows